data class WalletBalance(
    val amount: BigDecimal,
    val currency: String = "USD",
    val lastUpdated: Long = System.currentTimeMillis()
)

data class WalletTransaction(
    val id: String = UUID.randomUUID().toString(),
    val type: TransactionType,
    val amount: BigDecimal,
    val currency: String = "USD",
    val description: String,
    val timestamp: Long = System.currentTimeMillis(),
    val status: TransactionStatus = TransactionStatus.PENDING,
    val metadata: Map<String, String> = emptyMap()
)

enum class TransactionType {
    CREDIT, DEBIT, PURCHASE, REFUND, TOP_UP
}

enum class TransactionStatus {
    PENDING, PROCESSING, COMPLETED, FAILED, CANCELLED, REFUNDED
}

data class PurchaseItem(
    val productId: String,
    val name: String,
    val description: String,
    val price: BigDecimal,
    val currency: String = "USD",
    val type: PurchaseType = PurchaseType.ONE_TIME
)

enum class PurchaseType {
    ONE_TIME, SUBSCRIPTION
}

sealed class PaymentResult {
    data class Success(val transaction: WalletTransaction) : PaymentResult()
    data class Error(val code: Int, val message: String) : PaymentResult()
    data object Cancelled : PaymentResult()
    data object Pending : PaymentResult()
}

