class SecureStorage(private val context: Context) {

    companion object {
        private const val PREFS_FILE = "secure_payment_prefs"
        private const val KEY_WALLET_BALANCE = "wallet_balance"
        private const val KEY_TRANSACTIONS = "transactions"
        private const val KEY_USER_TOKEN = "user_token"
        private const val TAG = "SecureStorage"
    }

    private val gson = Gson()

    private val encryptedPrefs by lazy {
        try {
            val masterKey = MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()

            EncryptedSharedPreferences.create(
                context,
                PREFS_FILE,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
        } catch (e: Exception) {
            Log.e(TAG, "Failed to create EncryptedSharedPreferences, using fallback", e)
            // Fallback for older devices
            context.getSharedPreferences(PREFS_FILE, Context.MODE_PRIVATE)
        }
    }

    fun saveWalletBalance(balance: WalletBalance) {
        val json = gson.toJson(balance)
        encryptedPrefs.edit().putString(KEY_WALLET_BALANCE, json).apply()
    }

    fun getWalletBalance(): WalletBalance {
        val json = encryptedPrefs.getString(KEY_WALLET_BALANCE, null)
        return if (json != null) {
            gson.fromJson(json, WalletBalance::class.java)
        } else {
            WalletBalance(BigDecimal.ZERO)
        }
    }

    fun saveTransactions(transactions: List<WalletTransaction>) {
        val json = gson.toJson(transactions)
        encryptedPrefs.edit().putString(KEY_TRANSACTIONS, json).apply()
    }

    fun getTransactions(): List<WalletTransaction> {
        val json = encryptedPrefs.getString(KEY_TRANSACTIONS, null)
        return if (json != null) {
            val type = object : TypeToken<List<WalletTransaction>>() {}.type
            gson.fromJson(json, type)
        } else {
            emptyList()
        }
    }

    fun saveUserToken(token: String) {
        encryptedPrefs.edit().putString(KEY_USER_TOKEN, token).apply()
    }

    fun getUserToken(): String? {
        return encryptedPrefs.getString(KEY_USER_TOKEN, null)
    }

    fun clearAll() {
        encryptedPrefs.edit().clear().apply()
    }
}

