class WalletManager(
    private val context: Context,
    private val secureStorage: SecureStorage,
    private val securityManager: SecurityManager
) {
    companion object {
        private const val TAG = "WalletManager"
        private const val MAX_TRANSACTION_AMOUNT = 10000.0
        private const val MIN_TRANSACTION_AMOUNT = 0.01
    }

    private val _balance = MutableStateFlow(secureStorage.getWalletBalance())
    val balance: StateFlow<WalletBalance> = _balance.asStateFlow()

    private val _transactions = MutableStateFlow(secureStorage.getTransactions())
    val transactions: StateFlow<List<WalletTransaction>> = _transactions.asStateFlow()

    private val _lastResult = MutableLiveData<PaymentResult>()
    val lastResult: LiveData<PaymentResult> = _lastResult

    private val pendingTransactions = ConcurrentHashMap<String, WalletTransaction>()
    private val transactionLock = Any()

    private val coroutineScope = CoroutineScope(Dispatchers.IO + SupervisorJob())

    fun getBalance(): WalletBalance = _balance.value

    suspend fun topUp(amount: BigDecimal, description: String = "Wallet top-up"): PaymentResult {
        return processTransaction(
            type = TransactionType.TOP_UP,
            amount = amount,
            description = description
        )
    }

    suspend fun debit(amount: BigDecimal, description: String): PaymentResult {
        return processTransaction(
            type = TransactionType.DEBIT,
            amount = amount,
            description = description
        )
    }

    suspend fun purchaseWithWallet(item: PurchaseItem): PaymentResult {
        return processTransaction(
            type = TransactionType.PURCHASE,
            amount = item.price,
            description = "Purchase: ${item.name}",
            metadata = mapOf("product_id" to item.productId)
        )
    }

    suspend fun refund(originalTransactionId: String): PaymentResult {
        val originalTransaction = _transactions.value.find { it.id == originalTransactionId }
            ?: return PaymentResult.Error(404, "Original transaction not found")

        if (originalTransaction.status != TransactionStatus.COMPLETED) {
            return PaymentResult.Error(400, "Can only refund completed transactions")
        }

        return processTransaction(
            type = TransactionType.REFUND,
            amount = originalTransaction.amount,
            description = "Refund for: ${originalTransaction.description}",
            metadata = mapOf("original_transaction_id" to originalTransactionId)
        )
    }

    private suspend fun processTransaction(
        type: TransactionType,
        amount: BigDecimal,
        description: String,
        metadata: Map<String, String> = emptyMap()
    ): PaymentResult = withContext(Dispatchers.IO) {
        // Validate amount
        val validationError = validateAmount(amount)
        if (validationError != null) return@withContext validationError

        // Check sufficient balance for debits/purchases
        if (type == TransactionType.DEBIT || type == TransactionType.PURCHASE) {
            if (_balance.value.amount < amount) {
                return@withContext PaymentResult.Error(402, "Insufficient wallet balance")
            }
        }

        val transaction = WalletTransaction(
            type = type,
            amount = amount,
            description = description,
            status = TransactionStatus.PROCESSING,
            metadata = metadata
        )

        pendingTransactions[transaction.id] = transaction

        try {
            // Generate transaction token for idempotency
            val token = securityManager.generateTransactionToken()
            Log.d(TAG, "Processing transaction ${transaction.id} with token hash: ${securityManager.hashData(token)}")

            // Simulate processing delay (replace with actual API call)
            delay(500)

            // Verify transaction integrity
            val transactionHash = securityManager.hashData(
                "${transaction.id}:${transaction.amount}:${transaction.type}:${transaction.timestamp}"
            )

            synchronized(transactionLock) {
                val currentBalance = _balance.value.amount

                val newBalance = when (type) {
                    TransactionType.CREDIT, TransactionType.TOP_UP, TransactionType.REFUND ->
                        currentBalance + amount
                    TransactionType.DEBIT, TransactionType.PURCHASE ->
                        currentBalance - amount
                }

                if (newBalance < BigDecimal.ZERO) {
                    val failedTransaction = transaction.copy(status = TransactionStatus.FAILED)
                    updateTransactionList(failedTransaction)
                    return@withContext PaymentResult.Error(402, "Insufficient funds after recalculation")
                }

                val completedTransaction = transaction.copy(
                    status = TransactionStatus.COMPLETED,
                    metadata = metadata + ("hash" to transactionHash)
                )

                val updatedBalance = WalletBalance(
                    amount = newBalance,
                    currency = transaction.currency
                )

                // Persist atomically
                secureStorage.saveWalletBalance(updatedBalance)
                updateTransactionList(completedTransaction)

                _balance.value = updatedBalance
                pendingTransactions.remove(transaction.id)

                Log.d(TAG, "Transaction ${transaction.id} completed. New balance: $newBalance")

                val result = PaymentResult.Success(completedTransaction)
                _lastResult.postValue(result)
                return@withContext result
            }
        } catch (e: Exception) {
            Log.e(TAG, "Transaction failed", e)
            val failedTransaction = transaction.copy(status = TransactionStatus.FAILED)
            updateTransactionList(failedTransaction)
            pendingTransactions.remove(transaction.id)
            val result = PaymentResult.Error(500, "Transaction failed: ${e.message}")
            _lastResult.postValue(result)
            return@withContext result
        }
    }

    private fun validateAmount(amount: BigDecimal): PaymentResult.Error? {
        if (amount <= BigDecimal.ZERO) {
            return PaymentResult.Error(400, "Amount must be positive")
        }
        if (amount < BigDecimal(MIN_TRANSACTION_AMOUNT)) {
            return PaymentResult.Error(400, "Amount below minimum: $MIN_TRANSACTION_AMOUNT")
        }
        if (amount > BigDecimal(MAX_TRANSACTION_AMOUNT)) {
            return PaymentResult.Error(400, "Amount exceeds maximum: $MAX_TRANSACTION_AMOUNT")
        }
        return null
    }

    private fun updateTransactionList(transaction: WalletTransaction) {
        val currentTransactions = _transactions.value.toMutableList()
        val existingIndex = currentTransactions.indexOfFirst { it.id == transaction.id }
        if (existingIndex >= 0) {
            currentTransactions[existingIndex] = transaction
        } else {
            currentTransactions.add(0, transaction)
        }
        // Keep last 500 transactions in memory
        val trimmed = if (currentTransactions.size > 500) {
            currentTransactions.take(500)
        } else {
            currentTransactions
        }
        secureStorage.saveTransactions(trimmed)
        _transactions.value = trimmed
    }

    fun getTransactionById(id: String): WalletTransaction? {
        return _transactions.value.find { it.id == id }
    }

    fun getTransactionsByType(type: TransactionType): List<WalletTransaction> {
        return _transactions.value.filter { it.type == type }
    }

    fun getTransactionsByStatus(status: TransactionStatus): List<WalletTransaction> {
        return _transactions.value.filter { it.status == status }
    }

    fun destroy() {
        coroutineScope.cancel()
    }
}

