// Google Play Billing Manager - Handles in-app purchases
// ============================================================

class InAppPurchaseManager(
    private val context: Context,
    private val securityManager: SecurityManager
) : PurchasesUpdatedListener {

    companion object {
        private const val TAG = "InAppPurchaseManager"
    }

    private var billingClient: BillingClient? = null
    private val _billingResult = MutableStateFlow<BillingResult?>(null)
    val billingResult: StateFlow<BillingResult?> = _billingResult.asStateFlow()

    private val _isConnected = MutableStateFlow(false)
    val isConnected: StateFlow<Boolean> = _isConnected.asStateFlow()

    private val _availableProducts = MutableStateFlow<List<ProductDetails>>(emptyList())
    val availableProducts: StateFlow<List<ProductDetails>> = _availableProducts.asStateFlow()

    private val coroutineScope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    private var purchaseCallback: ((PaymentResult) -> Unit)? = null

    fun initialize() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()

        startConnection()
    }

    private fun startConnection() {
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(result: com.android.billingclient.api.BillingResult) {
                if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                    _isConnected.value = true
                    Log.d(TAG, "Billing client connected")
                    coroutineScope.launch {
                        queryExistingPurchases()
                    }
                } else {
                    _isConnected.value = false
                    _billingResult.value = BillingResult.Error(
                        result.responseCode,
                        result.debugMessage
                    )
                    Log.e(TAG, "Billing setup failed: ${result.debugMessage}")
                }
            }

            override fun onBillingServiceDisconnected() {
                _isConnected.value = false
                Log.w(TAG, "Billing service disconnected")
                // Retry connection with exponential backoff
                coroutineScope.launch {
                    delay(3000)
                    startConnection()
                }
            }
        })
    }

    suspend fun queryProducts(
        productIds: List<String>,
        productType: String = BillingClient.ProductType.INAPP
    ) {
        if (!_isConnected.value) {
            _billingResult.value = BillingResult.BillingUnavailable
            return
        }

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        val client = billingClient ?: return

        val result = withContext(Dispatchers.IO) {
            client.queryProductDetails(params)
        }

        if (result.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            val products = result.productDetailsList ?: emptyList()
            _availableProducts.value = products

            val purchaseItems = products.map { details ->
                val price = details.oneTimePurchaseOfferDetails?.let {
                    BigDecimal(it.priceAmountMicros).divide(BigDecimal(1_000_000))
                } ?: BigDecimal.ZERO

                val currency = details.oneTimePurchaseOfferDetails?.priceCurrencyCode ?: "USD"

                PurchaseItem(
                    productId = details.productId,
                    name = details.name,
                    description = details.description,
                    price = price,
                    currency = currency,
                    type = if (details.productType == BillingClient.ProductType.SUBS)
                        PurchaseType.SUBSCRIPTION else PurchaseType.ONE_TIME
                )
            }

            _billingResult.value = BillingResult.ProductsLoaded(purchaseItems)
        } else {
            _billingResult.value = BillingResult.Error(
                result.billingResult.responseCode,
                result.billingResult.debugMessage
            )
        }
    }

    fun launchPurchaseFlow(
        activity: Activity,
        productDetails: ProductDetails,
        callback: (PaymentResult) -> Unit
    ) {
        if (!_isConnected.value) {
            callback(PaymentResult.Error(-1, "Billing service not connected"))
            return
        }

        purchaseCallback = callback

        val productDetailsParamsList = listOf(
            BillingFlowParams.ProductDetailsParams.newBuilder()
                .setProductDetails(productDetails)
                .build()
        )

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(productDetailsParamsList)
            .build()

        val result = billingClient?.launchBillingFlow(activity, billingFlowParams)
        if (result?.responseCode != BillingClient.BillingResponseCode.OK) {
            callback(PaymentResult.Error(
                result?.responseCode ?: -1,
                result?.debugMessage ?: "Unknown error"
            ))
        }
    }

    fun launchPurchaseFlowByProductId(
        activity: Activity,
        productId: String,
        callback: (PaymentResult) -> Unit
    ) {
        val productDetails = _availableProducts.value.find { it.productId == productId }
        if (productDetails == null) {
            callback(PaymentResult.Error(404, "Product not found. Query products first."))
            return
        }
        launchPurchaseFlow(activity, productDetails, callback)
    }

    override fun onPurchasesUpdated(
        result: com.android.billingclient.api.BillingResult,
        purchases: MutableList<Purchase>?
    ) {
        when (result.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    coroutineScope.launch {
                        handlePurchase(purchase)
                    }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                purchaseCallback?.invoke(PaymentResult.Cancelled)
                _billingResult.value = BillingResult.Error(
                    result.responseCode,
                    "Purchase cancelled by user"
                )
            }
            else -> {
                purchaseCallback?.invoke(
                    PaymentResult.Error(result.responseCode, result.debugMessage)
                )
                _billingResult.value = BillingResult.Error(
                    result.responseCode,
                    result.debugMessage
                )
            }
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        // Verify purchase signature
        if (!verifyPurchase(purchase)) {
            Log.e(TAG, "Purchase verification failed for ${purchase.orderId}")
            purchaseCallback?.invoke(
                PaymentResult.Error(403, "Purchase verification failed")
            )
            return
        }

        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            // Acknowledge the purchase if not already acknowledged
            if (!purchase.isAcknowledged) {
                val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
                    .setPurchaseToken(purchase.purchaseToken)
                    .build()

                val ackResult = withContext(Dispatchers.IO) {
                    billingClient?.acknowledgePurchase(acknowledgePurchaseParams)
                }

                if (ackResult?.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d(TAG, "Purchase acknowledged: ${purchase.orderId}")
                    onPurchaseCompleted(purchase)
                } else {
                    Log.e(TAG, "Failed to acknowledge purchase: ${ackResult?.debugMessage}")
                    purchaseCallback?.invoke(
                        PaymentResult.Error(
                            ackResult?.responseCode ?: -1,
                            "Failed to acknowledge purchase"
                        )
                    )
                }
            } else {
                onPurchaseCompleted(purchase)
            }
        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            purchaseCallback?.invoke(PaymentResult.Pending)
        }
    }

    private fun onPurchaseCompleted(purchase: Purchase) {
        _billingResult.value = BillingResult.PurchaseComplete(purchase)

        val transaction = WalletTransaction(
            id = purchase.orderId ?: UUID.randomUUID().toString(),
            type = TransactionType.PURCHASE,
            amount = BigDecimal.ZERO, // Actual amount from product details
            description = "Google Play Purchase: ${purchase.products.joinToString()}",
            status = TransactionStatus.COMPLETED,
            metadata = mapOf(
                "purchase_token" to purchase.purchaseToken,
                "order_id" to (purchase.orderId ?: ""),
                "products" to purchase.products.joinToString(",")
            )
        )

        purchaseCallback?.invoke(PaymentResult.Success(transaction))
    }

    private fun verifyPurchase(purchase: Purchase): Boolean {
        // Verify the purchase signature
        // In production, this should be done server-side
        val signature = purchase.signature
        val originalJson = purchase.originalJson

        if (signature.isBlank() || originalJson.isBlank()) {
            return false
        }

        // Hash the purchase data for logging (never log raw purchase data)
        val purchaseHash = securityManager.hashData(originalJson)
        Log.d(TAG, "Verifying purchase with hash: $purchaseHash")

        // TODO: Send to backend for server-side verification
        // For now, basic client-side check
        return purchase.purchaseState == Purchase.PurchaseState.PURCHASED
    }

    suspend fun consumePurchase(purchaseToken: String): Boolean {
        val consumeParams = ConsumeParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()

        val result = withContext(Dispatchers.IO) {
            billingClient?.consumePurchase(consumeParams)
        }

        return result?.billingResult?.responseCode == BillingClient.BillingResponseCode.OK
    }

    private suspend fun queryExistingPurchases() {
        val client = billingClient ?: return

        val params = QueryPurchasesParams.newBuilder()
            .setProductType(BillingClient.ProductType.INAPP)
            .build()

        val result = withContext(Dispatchers.IO) {
            client.queryPurchasesAsync(params)
        }

        if (result.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            result.purchasesList.forEach { purchase ->
                if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
                    handlePurchase(purchase)
                }
            }
        }
    }

    fun destroy() {
        billingClient?.endConnection()
        billingClient = null
        coroutineScope.cancel()
    }
}

// ============================================================
// Rate Limiter - Prevents abuse
// ============================================================

class RateLimiter(
    private val maxRequests: Int = 10,
    private val windowMillis: Long = 60_000 // 1 minute
) {
    private val timestamps = mutableListOf<Long>()
    private val lock = Any()

    fun allowRequest(): Boolean {
        synchronized(lock) {
            val now = System.currentTimeMillis()
            timestamps.removeAll { now - it > windowMillis }
            return if (timestamps.size < maxRequests) {
                timestamps.add(now)
                true
            } else {
                false
            }
        }
    }

    fun remainingRequests(): Int {
        synchronized(lock) {
            val now = System.currentTimeMillis()
            timestamps.removeAll { now - it > windowMillis }
            return maxRequests - timestamps.size
        }
    }
}

// ============================================================
// Fraud Detection - Basic client-side fraud detection
// ============================================================

class FraudDetector(private val securityManager: SecurityManager) {

    companion object {
        private const val TAG = "FraudDetector"
        private const val RAPID_TRANSACTION_THRESHOLD = 5
        private const val RAPID_TRANSACTION_WINDOW_MS = 60_000L // 1 minute
        private const val HIGH_VALUE_THRESHOLD = 500.0
    }

    private val recentTransactions = mutableListOf<Pair<Long, BigDecimal>>()

    data class FraudCheckResult(
        val isAllowed: Boolean,
        val riskLevel: RiskLevel,
        val reason: String? = null
    )

    enum class RiskLevel {
        LOW, MEDIUM, HIGH, BLOCKED
    }

    fun checkTransaction(amount: BigDecimal, type: TransactionType): FraudCheckResult {
        val now = System.currentTimeMillis()

        // Clean old entries
        recentTransactions.removeAll { now - it.first > RAPID_TRANSACTION_WINDOW_MS }

        // Check rapid transactions
        if (recentTransactions.size >= RAPID_TRANSACTION_THRESHOLD) {
            Log.w(TAG, "Rapid transaction detected")
            return FraudCheckResult(
                isAllowed = false,
                riskLevel = RiskLevel.BLOCKED,
                reason = "Too many transactions in a short period"
            )
        }

        // Check high value
        if (amount > BigDecimal(HIGH_VALUE_THRESHOLD)) {
            Log.w(TAG, "High value transaction: $amount")
            recentTransactions.add(Pair(now, amount))
            return FraudCheckResult(
                isAllowed = true,
                riskLevel = RiskLevel.HIGH,
                reason = "High value transaction - additional verification recommended"
            )
        }

        // Check cumulative amount in window
        val totalInWindow = recentTransactions.sumOf { it.second } + amount
        if (totalInWindow > BigDecimal(1000)) {
            Log.w(TAG, "High cumulative amount in window: $totalInWindow")
            recentTransactions.add(Pair(now, amount))
            return FraudCheckResult(
                isAllowed = true,
                riskLevel = RiskLevel.MEDIUM,
                reason = "High cumulative transaction volume"
            )
        }

        recentTransactions.add(Pair(now, amount))
        return FraudCheckResult(
            isAllowed = true,
            riskLevel = RiskLevel.LOW
        )
    }
}

// ============================================================
// Payment Processor - Main entry point
// ============================================================

class PaymentProcessor private constructor(
    private val context: Context
) {
    companion object {
        private const val TAG = "PaymentProcessor"

        @Volatile
        private var instance: PaymentProcessor? = null

        fun getInstance(context: Context): PaymentProcessor {
            return instance ?: synchronized(this) {
                instance ?: PaymentProcessor(context.applicationContext).also {
                    instance = it
                }
            }
        }
    }

    val securityManager = SecurityManager(context)
    val secureStorage = SecureStorage(context)
    val walletManager = WalletManager(context, secureStorage, securityManager)
    val inAppPurchaseManager = InAppPurchaseManager(context, securityManager)
    val fraudDetector = FraudDetector(securityManager)
    val rateLimiter = RateLimiter()

    private val coroutineScope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    fun initialize() {
        inAppPurchaseManager.initialize()
        Log.d(TAG, "Payment processor initialized")
    }

    suspend fun processWalletPayment(
        amount: BigDecimal,
        description: String,
        type: TransactionType = TransactionType.DEBIT
    ): PaymentResult {
        // Rate limiting
        if (!rateLimiter.allowRequest()) {
            return PaymentResult.Error(429, "Too many requests. Please try again later.")
        }

        // Fraud detection
        val fraudCheck = fraudDetector.checkTransaction(amount, type)
        if (!fraudCheck.isAllowed) {
            return PaymentResult.Error(403, fraudCheck.reason ?: "Transaction blocked by fraud detection")
        }

        if (fraudCheck.riskLevel == FraudDetector.RiskLevel.HIGH) {
            Log.w(TAG, "High risk transaction proceeding: ${fraudCheck.reason}")
            // In production, you might want to trigger additional verification
        }

        return when (type) {
            TransactionType.TOP_UP -> walletManager.topUp(amount, description)
            TransactionType.DEBIT, TransactionType.PURCHASE -> walletManager.debit(amount, description)
            TransactionType.REFUND -> PaymentResult.Error(400, "Use refund method with transaction ID")
            TransactionType.CREDIT -> walletManager.topUp(amount, description)
        }
    }

    suspend fun purchaseProduct(
        activity: Activity,
        productId: String,
        callback: (PaymentResult) -> Unit
    ) {
        if (!rateLimiter.allowRequest()) {
            callback(PaymentResult.Error(429, "Too many requests. Please try again later."))
            return
        }

        inAppPurchaseManager.launchPurchaseFlowByProductId(activity, productId, callback)
    }

    suspend fun queryAvailableProducts(productIds: List<String>) {
        inAppPurchaseManager.queryProducts(productIds)
    }

    suspend fun refundTransaction(transactionId: String): PaymentResult {
        if (!rateLimiter.allowRequest()) {
            return PaymentResult.Error(429, "Too many requests. Please try again later.")
        }
        return walletManager.refund(transactionId)
    }

    fun getWalletBalance(): WalletBalance = walletManager.getBalance()

    fun getTransactionHistory(): List<WalletTransaction> = walletManager.transactions.value

    fun encryptSensitiveData(data: String): String = securityManager.encrypt(data)

    fun decryptSensitiveData(encryptedData: String): String = securityManager.decrypt(encryptedData)

    fun destroy() {
        walletManager.destroy()
        inAppPurchaseManager.destroy()
        coroutineScope.cancel()
        instance = null
        Log.d(TAG, "Payment processor destroyed")
    }
}

// ============================================================
// Extension functions for convenience
// ============================================================

fun Activity.getPaymentProcessor(): PaymentProcessor {
    return PaymentProcessor.getInstance(this)
}

suspend fun PaymentProcessor.quickPurchase(
    activity: Activity,
    productId: String
): PaymentResult = suspendCancellableCoroutine { continuation ->
    kotlinx.coroutines.runBlocking {
        purchaseProduct(activity, productId) { result ->
            if (continuation.isActive) {
                continuation.resume(result) {}
            }
        }
    }
}

private suspend fun <T> suspendCancellableCoroutine(
    block: (kotlinx.coroutines.CancellableContinuation<T>) -> Unit
): T = kotlinx.coroutines.suspendCancellableCoroutine(block)